import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[(pname, p['id'])] = p['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    proj, pkg = key
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((proj, pkg, bv))
    else:
        changes.append((proj, pkg, bv, av))

print('=== CHANGES ===')
if not changes:
    print('None - fully version-neutral')
else:
    for c in changes:
        print(f'{c[0]} | {c[1]} | {c[2]} -> {c[3]}')
print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} | {u[1]} | {u[2]}')
"

